import React, {useEffect} from 'react'
import ContactList from './components/ContactList'
import ChatWindow from './components/ChatWindow'
import { useStore } from './store'

export default function App(){
  const {openChats, setContacts} = useStore()

  useEffect(()=>{
    // sample contacts
    setContacts([{id:2,name:'Alice',online:true},{id:3,name:'Bob',online:false}])
  },[])

  return (
    <div className="min-h-screen flex">
      <ContactList />
      <main className="flex-1 p-4">Main app area</main>
      {openChats.map(c=> <ChatWindow key={c.id} chat={c} />)}
    </div>
  )
}
